function loadManifestsFromDir(manifestsDir: string): ManifestEntry[] {
  if (!existsSync(manifestsDir)) return []
  const manifests: ManifestEntry[] = []
  loadManifestsRecursive(manifestsDir, manifests)
  return manifests
